import React, { useState } from 'react'
import {  Table, Progress, Avatar, Button, Card, Col, Modal, Row, Upload } from 'antd';
import { EXCEL_CONSTANTS, STATUS } from '../../utils/constants'
import { containerConstantsService } from '../../utils/containerconstants/ContainerConstants';
import { CheckCircleFilled, InfoCircleFilled } from '@ant-design/icons';
import UploadExcelIcon from '../../images/excel_icon.svg'
import AddFormIcon from '../../images/add_form_icon.svg'
import AWBAddUploadModalStyle from './AWBAddUploadModalStyle.js';
import axios from 'axios';
import {BASE_PATH_APIS} from '../../utils/constants';
import { notifyResponseMessage } from '../commoncomponent/NotificationComponent/notifyResponseMessage';

const containerConstants = containerConstantsService.getInstance();
const { Dragger } = Upload;
const { Meta } = Card;


const AWBAddUploadModal = ({ showModalDialogAddUpload,setShowModalDialogAddUpload,setShowFormModalDialog, ...otherProps }) => {

    const [fileName, setFileName] = useState('');
    const [uploadResponse,setUploadResponse] = useState(null);
    const [errorData, setErrorData] = useState([]);
    const [visibleJsx,setVisibleJsx] = useState(EXCEL_CONSTANTS.INITIAL);
    const [progressWidth,setProgressWidth] = useState(0);

    const errorHeader = [
        {
          title: <div className='font-family-weight-500 font-s10 font-h16' style ={{color: '#727272'}}>ERROR MESSAGE</div>,
          dataIndex: 'errorMsg',
          key: 'errorMsg',
          render: text => <div className='font-family-weight-400 font-s12 font-h18' style = {{color: '#212121'}} >{text}</div>,
        }
    ];

    const downloadSample = async () => {
        axios({
          url:BASE_PATH_APIS.basePathForAPIS+'/app/rest/label_generation/download_sample_excel',
          method: 'GET',
          responseType: 'blob',
        }).then((response) => {
          if(response.status===200){
            const url = window.URL.createObjectURL(new Blob([response.data]));
            const link = document.createElement('a');
            link.href = url;

            link.setAttribute('download',containerConstants.formatString(containerConstants.ADD_AWB)+'.'+getExtension(response.data.type));
            document.body.appendChild(link);
            link.click();
          }
          else if(response.status===204){
            notifyResponseMessage(STATUS.ERROR,containerConstants.formatString(containerConstants.NO_SAMPLE_TEMPLATE_FOUND));

          }else {
            notifyResponseMessage(STATUS.ERROR,response.data);
          }
        })
        .catch(error => {
          notifyResponseMessage(STATUS.ERROR,containerConstants.formatString(containerConstants.SOMETHING_WENT_WRONG));
        });
    }

    const getExtension = (ext) =>{
        switch(ext){
            case 'application/ms-excel':
            return 'xlsx'

            default:
            break;
        }
    }

    const closeAwbNumMasterDialog = () => {
        setShowModalDialogAddUpload(false);
        otherProps.reloadPage();
    }

    const openFormModal = () => {
        setShowModalDialogAddUpload(false);
        otherProps.setShowCustomizedFormModalDialog({
            visible: true,
            okText: containerConstants.formatString(containerConstants.ADD),
            title: containerConstants.formatString(containerConstants.ADD_AWB)
        });
    }

    const props = {
        name: 'file',
        maxCount: 1,
        multiple: false,
        action: BASE_PATH_APIS.basePathForAPIS+'/app/rest/label_generation/upload_excel',
        onChange: info => {
            const status = info.file.status;
            if(fileName.localeCompare(info.file.name) !== 0){
            setFileName(info.file.name);
            }
            if (status === 'uploading') {
                setProgressWidth(info.file.percent)
                setVisibleJsx(EXCEL_CONSTANTS.UPLOADING)
            }else if (status === 'done') {
                setVisibleJsx(EXCEL_CONSTANTS.UPLOAD_RESPONSE);
                setUploadResponse(info.file.response);
                if(info.file.response.failCount > 0 || (info.file.response.errorMessageList && info.file.response.errorMessageList.length >0)){
                    let errors = [];
                        for (const [key, errorMessage] of Object.entries(info.file.response.errorMessageList)) {
                            errors.push({
                                key: '1',
                                errorMsg: errorMessage
                                });
                        }
                        setErrorData(errors);
                }
            } else if (status === 'error') {
                let error = '';
                if (info.file.response.status === 500) {
                    error = { status: 500, errorMessage: '' };
                    } else if (info.file.response.status === 404) {
                        error = {status: 404 ,errorMessage : info.file.response.error};
                } else if (info.file.response.responseMessage) {
                    error = { status: null, errorMessage: info.file.response.responseMessage };
                }
                setVisibleJsx(EXCEL_CONSTANTS.ERROR);
            }else if(status === 'removed'){
                setVisibleJsx(EXCEL_CONSTANTS.INITIAL)
            }
        },
        accept: '.xlsx,.xls',
    };



    return (
        <div>
            <AWBAddUploadModalStyle/>
        {visibleJsx === EXCEL_CONSTANTS.UPLOAD_RESPONSE
                && uploadResponse && uploadResponse!=null && uploadResponse.successCount > 0
                   ?
            <Modal
                className='master-data-add-modal'
                visible={showModalDialogAddUpload}
                style = {{width: '480px', height: '410px'}}
                footer={null}
                onOk={closeAwbNumMasterDialog}
                onCancel={closeAwbNumMasterDialog}
                bodyStyle = {{justifyContent : 'center'}}
            >

                <div >
                        <div style ={{width:'100%', justifyContent: 'center', display: 'flex'}}><CheckCircleFilled style ={{fontSize:40, color : '#279B4E'}} /></div>

                        <div style ={{width:'100%', marginTop: '16px', justifyContent: 'center', display: 'flex', color : '#000000'}} className = "font-family-weight-500 font-s18 font-h26">
                            {containerConstants.formatString(containerConstants.SUCCESSFULLY_UPLOADED)}
                        </div>
                        <div className = 'font-family-weight-400 font-s12 font-h18' style = {{justifyContent: 'center', display: 'flex'}}>{fileName}</div>

                        <div style ={{width:'100%', justifyContent: 'center', display: 'flex', color: '#727272'}} className="font-family-weight-400 font-s14 font-h22" >
                            {uploadResponse.successCount} {containerConstants.formatString(containerConstants.NEW_RECORDS_ARE_UPLOADED)}
                        </div>

                    {uploadResponse.failCount > 0 &&

                    <div>
                    <div style ={{width:'100%', alignItems: 'center', marginTop: '16px', marginBottom: '12px',  display: 'flex', background: '#FFFFFF', border: '1px solid #C84031', borderRadius: '5px'}} className="font-family-weight-400 font-s12 font-h26" >
                        <InfoCircleFilled style = {{marginRight: '10px', color:'#C84031', fontSize : 20}}/>  {uploadResponse.failCount} records from the file couldn't be added due to error. Please update the below records
                            </div>

                            <Table bordered columns={errorHeader} dataSource={errorData} pagination={false}/>
                    </div>
                    }
                    <div style ={{justifyContent: 'center', display: 'flex'}}>
                        <Button style ={{marginTop: '24px'}} type ='primary' onClick = {closeAwbNumMasterDialog}>
                            {containerConstants.formatString(containerConstants.CLOSE)}
                        </Button>
                    </div>
                </div>

            </Modal>
               :
            <Modal
                className='master-data-add-modal'
                title={containerConstants.formatString(containerConstants.ADD_AWB)}
                visible={showModalDialogAddUpload}
                style = {{width: '480px', height: '410px'}}
                footer={null}
                onOk={closeAwbNumMasterDialog}
                onCancel={closeAwbNumMasterDialog}
            >
                <Row>
                    <Col span={12}>
                        <Card
                            id='add-modal-excel-card'
                        >
                                <Dragger {...props} showUploadList={false}>
                                <Meta
                                    avatar={<Avatar shape='square' src={UploadExcelIcon} />}
                                    title={containerConstants.formatString(containerConstants.UPLOAD_EXCEL)}
                                    description={containerConstants.formatString(containerConstants.UPLOAD_EXCEL_DESCRIPTION)}
                                >
                                </Meta>
                            </Dragger>
                        </Card>

                        { visibleJsx === EXCEL_CONSTANTS.UPLOADING &&
                            <Progress showInfo={false} percent={progressWidth} />}

                        {visibleJsx === EXCEL_CONSTANTS.UPLOAD_RESPONSE &&
                            uploadResponse && uploadResponse!=null && uploadResponse.failCount > 0 &&


                            <div style = {{color: '#C84031'}}>
                                <div style = {{color: '#C84031'}} className = 'font-family-weight-400 font-s12 font-h18'>{fileName}</div>

                                {
                                    uploadResponse.errorMessageList.map(data=><Row>{data}</Row>)
                                }
                            </div>
                        }
                        { visibleJsx === EXCEL_CONSTANTS.UPLOAD_RESPONSE &&
                            uploadResponse && uploadResponse!=null && uploadResponse.failCount === 0 && errorData && errorData.length >0 &&

                            <div>
                                <div style = {{color: '#C84031'}} className = 'font-family-weight-400 font-s12 font-h18'>{fileName}</div>
                                    {errorData[0].errorMsg }
                            </div>
                        }

                </Col>
                <Col span={12}>
                    <Card
                        id='add-modal-form-card'
                        onClick={() => {openFormModal()
                            // setShowFormModalDialog({
                            //         visible: true,
                            //         title: containerConstants.formatString(containerConstants.ADD_AWB),
                            //         okText: 'OK'
                            // });
                            // setShowModalDialogAddUpload(false);
                        }}
                    >
                        <Meta
                            style={{height:43}}
                            avatar={<Avatar shape='square' src={AddFormIcon} />}
                            title={containerConstants.formatString(containerConstants.ADD_VIA_FORM)}
                            description={containerConstants.formatString(containerConstants.ADD_VIA_FORM_DESCRIPTION)}>
                        </Meta>
                    </Card>
                </Col>
            </Row>
                <Button type='link' onClick = {downloadSample}>
                {containerConstants.formatString(containerConstants.DOWNLOAD_TEMPLATE)}
            </Button>
        </Modal>

                    }


        </div>
    )
}

export default AWBAddUploadModal;
